import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { Card, Row, Col, Button, Image, Tag, Carousel, Modal } from "antd";
import { toast } from "react-toastify";
import { useDispatch, useSelector } from "react-redux";
import {
  getStoreProducts,
  deleteAProduct,
  resetState,
} from "../../features/product/productSlice";
import { BiEdit } from "react-icons/bi";
import { AiFillDelete } from "react-icons/ai";
import CustomModal from "../../components/CustomModal";

const StoreProducts = () => {
  const [open, setOpen] = useState(false);
  const [productId, setProductId] = useState("");
  const [expandedProducts, setExpandedProducts] = useState([]);
  const { id } = useParams();
  const dispatch = useDispatch();

  const { products, isLoading, error } = useSelector((state) => state.product);
  const user = useSelector((state) => state.auth.user);

  useEffect(() => {
    const fetchStoreProducts = async () => {
      try {
        if (id) {
          await dispatch(getStoreProducts(id));
        }
      } catch (error) {
        console.error("Error fetching products:", error);
        toast.error("Failed to load products.");
      }
    };

    fetchStoreProducts();
    dispatch(resetState());
  }, [dispatch, id]);

  const toggleDetails = (productId) => {
    setExpandedProducts((prevState) =>
      prevState.includes(productId)
        ? prevState.filter((id) => id !== productId)
        : [...prevState, productId],
    );
  };

  const showModal = (id) => {
    setOpen(true);
    setProductId(id);
  };

  const hideModal = () => {
    setOpen(false);
    setProductId("");
  };
  const [selectedProduct, setSelectedProduct] = useState(null);

  // Open Modal & Set Product Data
  const handleRowClick = (product) => {
    setSelectedProduct(product);
    setOpen(true);
  };

  // Close Modal
  const closeModal = () => setOpen(false);

  const deleteProductHandler = async (prodId) => {
    try {
      await dispatch(
        deleteAProduct({ productId: prodId, userId: user?._id }),
      ).unwrap();
      toast.success("Product has been deleted!");
      await dispatch(getStoreProducts(id));
    } catch (error) {
      console.error("Error deleting product:", error);
      toast.error("Failed to delete the product.");
    } finally {
      hideModal();
    }
  };

  return (
    <div className="container mx-auto px-6 py-8">
      <h3 className="text-3xl font-semibold text-gray-900 mb-6">
        🛒 Store Products
      </h3>

      {/* Table */}
      <div className="overflow-x-auto bg-white shadow-lg rounded-xl">
        <table className="w-full border-collapse">
          <thead className="bg-gray-800 text-white text-left">
            <tr>
              <th className="px-6 py-3">🖼️ Image</th>
              <th className="px-6 py-3">📛 Name</th>
              <th className="px-6 py-3">🏪 Store</th>
              <th className="px-6 py-3">💲 Price</th>
              <th className="px-6 py-3">🏷️ Category</th>
              <th className="px-6 py-3">📦 Stock</th>
            </tr>
          </thead>

          <tbody className="text-gray-700">
            {products && products.length > 0 ? (
              products.map((product) => (
                <tr
                  key={product._id}
                  className="border-b hover:bg-gray-100 transition-all cursor-pointer"
                  onClick={() => handleRowClick(product)}
                >
                  <td className="px-6 py-4">
                    {product.colors?.[0]?.images?.length > 0 ? (
                      <img
                        src={product.colors[0].images[0].secure_url}
                        alt="Product"
                        className="w-16 h-16 object-cover rounded-md"
                      />
                    ) : (
                      <span className="text-gray-400">No Image</span>
                    )}
                  </td>
                  <td className="px-6 py-4 font-medium">{product.title}</td>
                  <td className="px-6 py-4">
                    {product.store?.storeName || "N/A"}
                  </td>
                  <td className="px-6 py-4 text-green-600 font-semibold">
                    ${product.price}
                  </td>
                  <td className="px-6 py-4">{product.category}</td>
                  <td className="px-6 py-4">
                    {product.quantity > 0 ? (
                      <span className="text-green-500 font-medium">
                        {product.quantity} in stock
                      </span>
                    ) : (
                      <span className="text-red-500 font-medium">
                        Out of stock
                      </span>
                    )}
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="7" className="text-center text-gray-500 py-6">
                  No products found. 😞
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Product Details Modal */}
      <Modal
        title="📦 Product Details"
        visible={open}
        onCancel={closeModal}
        footer={[
          <Button
            key="close"
            onClick={closeModal}
            className="bg-gray-700 text-white"
          >
            Close
          </Button>,
        ]}
      >
        {selectedProduct && (
          <div className="p-4">
            {/* Image Preview */}
            <div className="mb-4">
              {selectedProduct.colors?.[0]?.images?.length > 0 ? (
                <img
                  src={selectedProduct.colors[0].images[0].secure_url}
                  alt="Product Preview"
                  className="w-full h-60 object-cover rounded-md"
                />
              ) : (
                <div className="text-center bg-gray-200 rounded-lg p-4">
                  No Image Available
                </div>
              )}
            </div>

            {/* Product Info */}
            <h2 className="text-2xl font-semibold">{selectedProduct.title}</h2>
            <p className="text-gray-600 mb-2">
              🏪 <strong>Store:</strong>{" "}
              {selectedProduct.store?.storeName || "N/A"}
            </p>
            <p className="text-green-600 font-semibold text-lg">
              💲 <strong>Price:</strong> ${selectedProduct.price}
            </p>
            <p className="mb-2">
              🏷️ <strong>Category:</strong> {selectedProduct.category}
            </p>
            <p className="mb-2">
              📦 <strong>Stock:</strong>{" "}
              {selectedProduct.quantity > 0
                ? selectedProduct.quantity + " in stock"
                : "Out of stock"}
            </p>
            <p className="mb-4">
              🔖 <strong>Brand:</strong> {selectedProduct.brand}
            </p>

            {/* Tags */}
            {selectedProduct.tags?.length > 0 && (
              <div className="mb-4">
                <strong>🏷️ Tags:</strong>
                <div className="mt-1 flex flex-wrap gap-2">
                  {selectedProduct.tags.map((tag, index) => (
                    <span
                      key={index}
                      className="bg-gray-200 px-2 py-1 rounded-md text-sm"
                    >
                      {tag}
                    </span>
                  ))}
                </div>
              </div>
            )}

            {/* Description */}
            {selectedProduct.description && (
              <div>
                <strong>📄 Description:</strong>
                <p className="mt-2 text-gray-700">
                  {selectedProduct.description}
                </p>
              </div>
            )}
          </div>
        )}
      </Modal>
    </div>
  );
};

export default StoreProducts;
